// Validar y extraer informe_id
const body = $input.item.json.body || $input.item.json;

if (!body.informe_id) {
  throw new Error('Falta informe_id en el request');
}

return [{
  json: {
    informe_id: body.informe_id
  }
}];

// Preparar datos del informe
const respuesta = $input.item.json;
const informe = Array.isArray(respuesta) ? respuesta[0] : respuesta;

if (!informe || !informe.id) {
  throw new Error('No se encontró el informe en Supabase');
}

// Obtener observaciones si están en observaciones_enumeradas
let observaciones = [];
if (informe.observaciones_enumeradas && Array.isArray(informe.observaciones_enumeradas)) {
  observaciones = informe.observaciones_enumeradas;
}

// Formatear fechas
const formatearFecha = (fecha) => {
  if (!fecha) return 'No definida';
  try {
    return new Date(fecha).toLocaleDateString('es-ES', {
      year: 'numeric',
      month: 'long',
      day: 'numeric'
    });
  } catch {
    return fecha;
  }
};

// Obtener nombres de usuarios (si están disponibles en el informe)
let elaboradoPorNombre = 'No especificado';
let aprobadoPorNombre = null;

// Intentar obtener nombres de usuarios si hay IDs
if (informe.elaborado_por_user && informe.elaborado_por_user.full_name) {
  elaboradoPorNombre = informe.elaborado_por_user.full_name;
} else if (informe.elaborado_por) {
  // Si solo hay ID, usar un valor por defecto
  elaboradoPorNombre = 'Auditor';
}

if (informe.aprobado_por_user && informe.aprobado_por_user.full_name) {
  aprobadoPorNombre = informe.aprobado_por_user.full_name;
} else if (informe.aprobado_por) {
  aprobadoPorNombre = 'Aprobador';
}

// Preparar contenido estructurado para Google Docs
const contenido = {
  informe_id: informe.id,
  auditoria_id: informe.auditoria_id,
  titulo: informe.encabezado || 'INFORME DE AUDITORÍA',
  encabezado: {
    de: informe.de || 'No especificado',
    para: informe.para || 'No especificado',
    asunto: informe.asunto || 'No especificado',
    fecha: formatearFecha(informe.fecha_inicio_informe)
  },
  secciones: [
    {
      titulo: 'ANTECEDENTES',
      contenido: informe.antecedentes || ''
    },
    {
      titulo: 'OBJETIVOS',
      contenido: informe.objetivos || ''
    },
    {
      titulo: 'ALCANCE',
      contenido: informe.alcance || ''
    },
    {
      titulo: 'RESULTADOS DE LA REVISIÓN',
      contenido: informe.resultados_revision || ''
    },
    {
      titulo: 'METODOLOGÍA APLICADA',
      contenido: informe.metodologia_aplicada || ''
    }
  ].filter(sec => sec.contenido),
  observaciones: observaciones.map((obs, idx) => ({
    numero: obs.numero || idx + 1,
    titulo: obs.titulo || '',
    descripcion: obs.descripcion || '',
    recomendacion: obs.recomendacion || ''
  })),
  estrategia: {
    texto: informe.estrategia || '',
    fecha_inicio: formatearFecha(informe.fecha_inicio_implementacion),
    fecha_fin: formatearFecha(informe.fecha_fin_implementacion),
    entregable: informe.entregable || ''
  },
  conclusiones: informe.conclusiones || '',
  recomendaciones_generales: informe.recomendaciones_generales || '',
  firmas: {
    elaborado_por: elaboradoPorNombre,
    fecha_elaboracion: formatearFecha(informe.fecha_elaboracion),
    aprobado_por: aprobadoPorNombre,
    fecha_aprobacion: formatearFecha(informe.fecha_aprobacion)
  }
};

return [{
  json: contenido
}];

// Generar requests para batchUpdate de Google Docs (versión simplificada)
const data = $('Code - Preparar Datos Estructurados').item.json;
const docId = $json.documentId;

if (!docId) {
  throw new Error('No se obtuvo documentId del documento creado');
}

const requests = [];
let currentIndex = 1;

// Construir todo el texto primero
let textoCompleto = '';

// 1. Encabezado
textoCompleto += `De: ${data.encabezado.de}\n`;
textoCompleto += `Para: ${data.encabezado.para}\n`;
textoCompleto += `Asunto: ${data.encabezado.asunto}\n`;
textoCompleto += `Fecha: ${data.encabezado.fecha}\n\n`;

// 2. Secciones
let seccionNum = 1;
for (const seccion of data.secciones) {
  textoCompleto += `${seccionNum}. ${seccion.titulo}\n`;
  textoCompleto += `${seccion.contenido}\n\n`;
  seccionNum++;
}

// 3. Observaciones
if (data.observaciones.length > 0) {
  textoCompleto += `${seccionNum}. OBSERVACIONES\n`;
  for (const obs of data.observaciones) {
    textoCompleto += `OBSERVACIÓN N° ${obs.numero}\n`;
    if (obs.titulo) textoCompleto += `Título: ${obs.titulo}\n`;
    if (obs.descripcion) textoCompleto += `Descripción: ${obs.descripcion}\n`;
    if (obs.recomendacion) textoCompleto += `Recomendación: ${obs.recomendacion}\n\n`;
  }
  seccionNum++;
}

// 4. Estrategia
if (data.estrategia.texto) {
  textoCompleto += `${seccionNum}. ESTRATEGIA DE IMPLEMENTACIÓN\n`;
  textoCompleto += `${data.estrategia.texto}\n`;
  if (data.estrategia.fecha_inicio) textoCompleto += `Fecha de inicio: ${data.estrategia.fecha_inicio}\n`;
  if (data.estrategia.fecha_fin) textoCompleto += `Fecha de fin: ${data.estrategia.fecha_fin}\n`;
  if (data.estrategia.entregable) textoCompleto += `Entregable: ${data.estrategia.entregable}\n\n`;
  seccionNum++;
}

// 5. Conclusiones
if (data.conclusiones) {
  textoCompleto += `${seccionNum}. CONCLUSIONES\n`;
  textoCompleto += `${data.conclusiones}\n\n`;
  seccionNum++;
}

// 6. Recomendaciones
if (data.recomendaciones_generales) {
  textoCompleto += `${seccionNum}. RECOMENDACIONES GENERALES\n`;
  textoCompleto += `${data.recomendaciones_generales}\n\n`;
}

// 7. Firmas
textoCompleto += 'FIRMAS\n';
textoCompleto += `Elaborado por: ${data.firmas.elaborado_por}\n`;
textoCompleto += `Fecha de elaboración: ${data.firmas.fecha_elaboracion}\n`;
if (data.firmas.aprobado_por) {
  textoCompleto += `Aprobado por: ${data.firmas.aprobado_por}\n`;
  textoCompleto += `Fecha de aprobación: ${data.firmas.fecha_aprobacion}\n`;
}

// Insertar todo el texto de una vez
requests.push({
  insertText: {
    location: { index: currentIndex },
    text: textoCompleto
  }
});

// Aplicar formato básico: hacer negritas en títulos y etiquetas
// Usar expresiones regulares para encontrar patrones
const lineas = textoCompleto.split('\n');
let charIndex = currentIndex;

for (let i = 0; i < lineas.length; i++) {
  const linea = lineas[i];
  const esTituloSeccion = /^\d+\.\s+[A-ZÁÉÍÓÚÑ\s]+$/.test(linea.trim());
  const esObservacion = /^OBSERVACIÓN N°/.test(linea.trim());
  const esFirma = /^FIRMAS$/.test(linea.trim());
  const esEtiqueta = /^(De:|Para:|Asunto:|Fecha:|Título:|Descripción:|Recomendación:|Fecha de inicio:|Fecha de fin:|Entregable:|Elaborado por:|Fecha de elaboración:|Aprobado por:|Fecha de aprobación:)/.test(linea.trim());

  if (esTituloSeccion || esObservacion || esFirma) {
    const startIdx = charIndex;
    const endIdx = charIndex + linea.length;

    requests.push({
      updateTextStyle: {
        range: { startIndex: startIdx, endIndex: endIdx },
        textStyle: { bold: true, fontSize: { magnitude: 14, unit: 'PT' } },
        fields: 'bold,fontSize'
      }
    });
  } else if (esEtiqueta) {
    // Solo la etiqueta en negrita, no el valor
    const match = linea.match(/^([^:]+:)/);
    if (match) {
      const etiquetaLength = match[1].length;
      const startIdx = charIndex;
      const endIdx = charIndex + etiquetaLength;

      requests.push({
        updateTextStyle: {
          range: { startIndex: startIdx, endIndex: endIdx },
          textStyle: { bold: true },
          fields: 'bold'
        }
      });
    }
  }

  charIndex += linea.length + 1; // +1 por el \n
}

return [{
  json: {
    documentId: docId,
    requests: requests
  }
}];

// Preparar respuesta final
const resultado = {
  success: true,
  informe_id: $('Code - Preparar Datos Estructurados').item.json.informe_id,
  document_id: $('HTTP Request - Crear Google Docs').item.json.documentId,
  documento_word_url: $('HTTP Request - Actualizar URL en Supabase').item.json[0]?.documento_word_url || null,
  mensaje: 'Documento Google Docs generado exitosamente'
};

return [{
  json: resultado
}];
